public static long[][] solve(long[][] grid, long x, long y, long k) {
    int startX = (int) x;
    int startY = (int) y;
    int len = (int) k;

    for (int i = 0; i < len / 2; i++) {
        int top = startX + i;
        int bottom = startX + len - 1 - i;
        for (int j = 0; j < len; j++) {
            int col = startY + j;
            long temp = grid[top][col];
            grid[top][col] = grid[bottom][col];
            grid[bottom][col] = temp;
        }
    }
    return grid;
}
```

